class Solution(object):
    def validSequence(self, word1, word2):
        n, m = len(word1), len(word2)
        # Compute suffix: suf[i] = longest suffix of word2 that matches as subsequence of word1[i..]
        suf = [0] * (n + 1)
        j = m - 1
        for i in range(n - 1, -1, -1):
            suf[i] = suf[i + 1]
            if j >= 0 and word1[i] == word2[j]:
                suf[i] = suf[i + 1] + 1
                j -= 1
        # suf[i] = number of chars from end of word2 matched as subsequence of word1[i..]
        # Recompute properly
        suf = [0] * (n + 1)
        j = m - 1
        for i in range(n - 1, -1, -1):
            if j >= 0 and word1[i] == word2[j]:
                suf[i] = suf[i + 1] + 1
                j -= 1
            else:
                suf[i] = suf[i + 1]

        # Greedily build answer: match prefix of word2 exactly, then use one free change
        result = []
        matched = 0  # how many chars of word2 matched so far (exactly)
        used_change = False
        for i in range(n):
            if used_change:
                break
            # Try to match word2[matched] exactly
            if word1[i] == word2[matched]:
                result.append(i)
                matched += 1
                if matched == m:
                    return result
            # Can we use the free change here?
            elif suf[i + 1] >= m - matched - 1:
                # Change word1[i] to word2[matched], then match rest as subsequence
                result.append(i)
                matched += 1
                used_change = True
                if matched == m:
                    return result
                # Match remaining word2[matched..] as subsequence of word1[i+1..]
                for ii in range(i + 1, n):
                    if word1[ii] == word2[matched]:
                        result.append(ii)
                        matched += 1
                        if matched == m:
                            return result
                return []
        return [] if matched < m else result
